text:
(In reply to Alexander V. Chernikov from comment #2)
I provided minimal configuration that can be used to reproduce the issue.
My full jail configuration for testing purpose looks like this:


# cat /etc/jail.conf
path = "/usr/jail/${name}";

exec.clean;
exec.prestart   = "ifconfig epair${epairid} create";
exec.prestart  += "ifconfig epair${epairid}a inet6 ifdisabled up";
exec.prestart  += "ifconfig bridge0 addm epair${epairid}a";
exec.created    = "cpuset -l 1 -j ${name}";
exec.start      = "ifconfig epair${epairid}b ether 02:ef:a4:c1:60:0${epairid}";
exec.start     += "ifconfig epair${epairid}b inet ${ipaddress} netmask ${netmask}";
exec.start     += "route add default ${gateway}";
exec.start     += "sh /etc/rc";
exec.stop       = "sh /etc/rc.shutdown jail";
exec.poststop   = "ifconfig epair${epairid}a destroy";

host.hostname   = "${name}";
mount.fstab     = "/etc/fstab.${name}";
mount.devfs;

vnet;
vnet.interface  = "epair${epairid}b";

test {
    $epairid    = 1;
    $ipaddress  = 192.168.0.101;
    $netmask    = 255.255.255.0;
    $gateway    = 192.168.0.1;
}


